// Create the user-assigned identity as its own resource
resource sharedIdentity 'Microsoft.ManagedIdentity/userAssignedIdentities@2023-01-31' = {
  name: 'my-shared-identity'
  location: resourceGroup().location
}

// Output the values needed for role assignments and attachment
output identityResourceId string = sharedIdentity.id
output principalId string = sharedIdentity.properties.principalId
output clientId string = sharedIdentity.properties.clientId

resource myVm 'Microsoft.Compute/virtualMachines@2023-03-01' = {
  name: 'MyVM'
  location: resourceGroup().location
  identity: {
    type: 'UserAssigned'
    userAssignedIdentities: {
      '${sharedIdentity.id}': {}   // attach the user-assigned identity
    }
  }
  properties: {
    // ... other VM properties
  }
}

# 1. Create the user-assigned identity
resource "azurerm_user_assigned_identity" "shared" {
  name                = "my-shared-identity"
  resource_group_name = azurerm_resource_group.rg.name
  location            = azurerm_resource_group.rg.location
}

# 2. Assign Key Vault Secrets User to the identity
resource "azurerm_role_assignment" "kv_access" {
  scope                = azurerm_key_vault.kv.id
  role_definition_name = "Key Vault Secrets User"
  principal_id         = azurerm_user_assigned_identity.shared.principal_id
}

# 3. Attach to VM — one role assignment serves all VMs that share this identity
resource "azurerm_linux_virtual_machine" "vm" {
  count               = 3
  name                = "app-vm-${count.index}"
  resource_group_name = azurerm_resource_group.rg.name
  location            = azurerm_resource_group.rg.location
  size                = "Standard_B2s"

  identity {
    type         = "UserAssigned"
    identity_ids = [azurerm_user_assigned_identity.shared.id]
  }
  # ... other required properties
}

resource myVm 'Microsoft.Compute/virtualMachines@2023-03-01' = {
  name: 'MyVM'
  location: resourceGroup().location
  identity: {
    type: 'SystemAssigned, UserAssigned'   // both types simultaneously
    userAssignedIdentities: {
      '${sharedIdentity.id}': {}
    }
  }
  properties: { /* ... */ }
}
